   Chain (G71000:G71050:SUB060) HSG73LF1;
   If %Found(HSG73LF1);
      loadClaim();
      If G73280 = *Blanks;
         DoW Not *In12;
            ExFmt HS1212W5;
            If *In04;
               *In78 = *On;
               FLAG04 = 'HS1212WT';
               loadText('GPT');
               ExSr SR04;
               *In78 = *Off;
            EndIf;
         EndDo;
      Else;
         *In25 = *On;
         ExFmt HS1212WK;
         *In25 = *Off;
      EndIf;
   EndIf;
  EndSr;
