C**************************************************************************
C* AUSWAHL 15 - A N Z E I G E  C L A I M  I N  S C A S -
C**************************************************************************
  BegSr SR115;
   G7305A = G71050;
   G7306A = SUB060;
   Chain(N) KEYG73 HSG73PF;
   If %FOUND(HSG73PF);
      If isWarrScope(G73140) And G71190 <> *Blanks;
         RESTXT = getCwpMsg('':G73430:G73440);
         FLTTXT = getCwpMsg('':G73450:G73460);
         RPYTXT = getCwpMsg('':G73470:G73480);
         EXPTXT = getCwpMsg('':G73490:G73500);
         CLAIMREQ = getClaimValues('Requested':G71000:G71050:
                                   SUB060:SUB065);
         CLAIMCMP = getClaimValues('Compensated':G71000:G71050:
                                   SUB060:SUB065);
         //Check if claim contains requested parts
         MIAINF = *Blanks;
         If isPartRequest(G71000:G71050:SUB060:SUB065);
            MIAINF = getCwpMsg('':'00':'00001');
         EndIf;
         REPTXT = *Blanks;
         *In69 = *Off;
         Chain KEYGPS HSG74F;
         If %FOUND(HSG74F);
            REPTXT = G74_TXT;
         EndIf;
         If REPTXT <> *Blanks;
            *In69 = *On;
         EndIf;
         If G73290 > 10 And G73290 < 17;
            exec sql
                 select G78_TXT into :reptxt from HSG78F
                        where G78_KZL = :G73000 And G78_CNR = :G73050 And
                              G78_FNR = :G73060 And G78_WNR = :G73065;
            If G73290 = 11;
               RESTXT = 'SDE Pr�fung - Antrag wird bearbeitet';
            EndIf;
            If G73290 = 12;
               RESTXT = 'SDE Pr�fung - Antrag genehmigt';
            EndIf;
            If G73290 = 16;
               RESTXT = 'SDE Pr�fung - Antrag abgelehnt';
            EndIf;
            FLTTXT = 'Siehe F11 Kommentar Bearbeiter';
            RPYTXT = *Blanks;
            EXPTXT = *Blanks;
            *In69 = *On;
         EndIf;
         Write HS1212WW;
         DoW Not *In12;
            ExFmt HS1212WW;
            If *In11;
               ExFmt HS1212WD;
            EndIf;
         EndDo;
      Else;
         //*Pr�fen ob abweichende Fehler-Nr. SDE
         If G71160 <> *BLANKS And SUB060 <> *BLANKS And SUBSTA < '30';
            If G73340 <> *Blanks;
               CallHS1212C1(G71160:G73340);
            Else;
               CallHS1212C1(G71160:SUB060);
            EndIf;
         Else;
            //*Fehler anzeigen
            If G71170 = 20 AND SUBSTA > '05';
               KEY0012 = %Dec(G71050:8:0);
               KEY0013 = %Dec(SUB060:2:0);
               SetGt KEY001 SDE001;
               ReadP(N) SDE00101;
               If Not %Eof(SDE001) And DEALNO = KEY0011 And
                  DCLMNO = KEY0012 And DFAINO = KEY0013;
                  ExFmt HS1212W9;
               Else;
                  MSG001 = TXTDEL11 + TXTDEL12;
                  MSG002 = TXTDEL21 + TXTDEL22;
                  MSG003 = TXTDEL31 + TXTDEL32;
                  ExFmt HS1212W9;
               EndIf;
            Else;
               //C*Kein Claim und kein Fehler
               MSG001 = *BLANKS;
               MSG002 = 'Fehler !!!';
               MSG003 = *BLANKS;
               ExFmt HS1212W9;
            EndIf;
         EndIf;
      EndIf;
   EndIf;
  EndSr;
  //**************************************************************************
  //* AUSWAHL 17 - G U T S C H R I F T    A N Z E I G E N -
  //**************************************************************************
  BegSr SR117;
   If SUBGUT <> *Blanks;
      Select;
      When %Subst(GetScope(SUB140):1:1) = 'A';
         GUTART = 'A';
         CallHs1212C3(GUTART:SUBGUT);
      When %Subst(GetScope(SUB140):1:1) = 'R';
         GUTART = 'R';
         CallHs1212C3(GUTART:SUBGUT);
      Other;
         GUTART = 'D';
         CallHs1295(GUTART:SUBGUT:Reprint);
         Monitor;
            Cmd = 'DSPSPLF GAAUSG * *LAST';
            CmdLen = %Len(Cmd);
            QCmdExc(Cmd:CmdLen);
            Cmd = 'DLTSPLF FILE(GAAUSG) SPLNBR(*LAST)';
            CmdLen = %Len(Cmd);
            QCmdExc(Cmd:CmdLen);
         On-Error *All;
         EndMon;
      EndSl;
   EndIf;
  EndSr;
  //**************************************************************************
  //* AUSWAHL 20 - F O L G E A N T R A G -
  //**************************************************************************
  BegSr SR120;
   VGLDAT2 = AKTDAT - %Days(TAGE);
   If isWarrScope(SUB140);
     If SUBSTA > '03';
        VGLDAT1 = AKTDAT - %Days(TAGE);
        ExSr SR120A;
     EndIf;
   Else;
      //*Zeitlimit pr�fen (14 Tage ab Gutschriftsdatum)
      CLANO8 = %Dec(G71050:8:0);
      FAINO = SUB060;
      If CLANO8 < 999999;
         CLANO6 = %Dec(%Subst(G71050:3:6):6:0);
         Chain (KEY0011:CLANO6:FAINO) S3L004H;
         If %FOUND(S3L004H) And CRDTDD <> 0;
            VGLDAT1 = %DATE(CRDTDD:*ISO);
            ExSr SR120A;
         EndIf;
      Else;
         Chain (CLANO8:%Dec(SUB060:2:0):KEY0011) S3F004;
         If %FOUND(S3F004) And CRDTDD <> 0;
            VGLDAT1 = %DATE(CRDTDD:*ISO);
            ExSr SR120A;
         EndIf;
      EndIf;
   EndIf;
  EndSr;
  //**************************************************************************
  //* Folgeantrag in Dateien speichern
  //**************************************************************************
  BegSr SR120A;
   If VGLDAT2 > VGLDAT1;
      Chain (G71000:G71010:G71020) HSG70F;
      If Not %Found(HSG70F) Or G70_STATUS = *Blanks;
         ExFmt HS1212WZ;
         LeaveSr;
      EndIf;
   EndIf;
   KOPIECNR = G71050;
   SUB060N = %Dec(SUB060:2:0);
   Chain (G7100P:G71050:SUB060) HSG73LF1;
   Dow %Found(HSG73LF1) And SUB060N < 100;
      SUB060N = SUB060N + 10;
      Chain (G7100P:G71050:%Char(SUB060N)) HSG73LF1;
   EndDo;
   //*Falls keine freie Fehler-Nr. vorhanden
   If %Found(HSG73LF1) Or SUB060N > 99;
      ExFmt HS1212WM;
    Else;
      //*Neue Fehler-Nr. erstellen
      G7305A = KOPIECNR;
      G7306A = SUB060;
      Chain KEYG73 HSG73PF;
      If %Found(HSG73PF);
         G73060 = %Char(SUB060N);
         G73065 = '0' + %Subst(%Char(SUB060N):1:1);
         G73290 = 0;
         G73340 = *BLANKS;
         G73420 = *BLANKS;
         G73430 = *BLANKS;
         G73440 = *BLANKS;
         G73450 = *BLANKS;
         G73460 = *BLANKS;
         G73470 = *BLANKS;
         G73480 = *BLANKS;
         G73490 = *BLANKS;
         G73500 = *BLANKS;
         Write HSG73PR;
      EndIf;
      //*N�chste Zeilen-Nr. ermitteln
      ExSr SR_ZEILE;
      //*Neuen Postens�tze erstellen
      G73060 = SUB060;
      SetLl KEYGPS HSGPSPF;
      ReadE(N) KEYGPS HSGPSPF;
      DoW Not %EoF(HSGPSPF);
         GPS010 = G71050;
         GPS020 = %Char(SUB060N);
         GPS025 = '0' + %Subst(GPS020:1:1);
         ZEILE += 1;
         GPS030 = ZEILE;
         GPS160 = *Blanks;
         GPS161 = *Blanks;
         GPS162 = *Blanks;
         GPS170 = 0;
         GPS180 = 0;
         GPS190 = 0;
         GPS200 = 0;
         GPS210 = 0;
         GPS220 = *Blanks;
         GPS230 = *Blanks;
         GPS240 = *Blanks;
         Write HSGPSPR;
         ReadE(N) KEYGPS HSGPSPF;
      EndDo;
      //*Anh�nge kopieren
      SUB060A = %Char(SUB060N);
      exec sql
         update HSG75F set G75_failNo = :SUB060A, G75_UPLTIME = null
         where g75_kzl = :G73000 And G75_claimNo = :G73050 and
              G75_failNo = :G73060;
   EndIf;
  EndSr;
  //**************************************************************************
  //* BEFEHLSTASTE 04 - B E D I E N E R F � H R U N G -
  //**************************************************************************
  BegSr SR04;
  F11TXT = *Blanks;
  If FLAG04 = 'HS1212W6' AND FLAGX4 = 'C4 ';
     F11TXT = F110;
  EndIf;
  Dow Not *In12;
     *IN90 = *Off;
     *IN99 = *On;
     ZLA = 0;
     Write HS1212CA;
     *IN99 = *OFF;
     Select;
     //* CLAIM TYP
     When FLAG04 = 'HS1212W6' AND FLAGX4 = '24A';
        DATTXT = DATTX1;
        DATTOP = DATTO1;
        For X = 1 To 6;
           DATA = *Blanks;
           DATA = TYP(X);
           ZLA += 1;
           MARKA = *Blanks;
           Write HS1212SA;
        EndFor;
     //* EPS
     When FLAG04 = 'HS1212W6' AND FLAGX4 = 'EPS';
        resultCode = EpsReq('':'':G71060:%Char(G71110):%Char(G71090):
                           G71030:G71040:%Char(G71100):G7307A:'':' ':'Y');
        EpsInfo = displayEpsInfo(G71060:%Char(G71110):G71000:G71050:
                                 G7308A:G7307A);
        If EpsInfo <> *Blanks;
           A_EPS  = %Subst(EpsInfo:1:20);
           G7307A = %Subst(EpsInfo:23:7);
           G7308A = %Subst(EpsInfo:21:2);
           *In37 = *On;
        EndIf;
     //* Codes
     When FLAG04 = 'HS1212W6' AND FLAGX4 = 'C1 ';
        DATTXT = DATTXT_C1;
        DATTOP = DATTOP_C1;
        SetLl (locale:%Dec(C1:5:0)) CWPMSGF;
        ReadE (locale:%Dec(C1:5:0)) CWPMSGF;
        Dow Not %Eof(CWPMSGF);
           If AktDat > MSG_FROM And AktDat < MSG_TO;
              MSG_IDC = %Char(MSG_ID);
              DATA = MSG_IDC + ' ' + MSG_TXT;
              ZLA += 1;
              MARKA = *Blanks;
              Write HS1212SA;
           EndIf;
           ReadE (locale:%Dec(C1:5:0)) CWPMSGF;
        EndDo;
     When FLAG04 = 'HS1212W6' AND FLAGX4 = 'C2 ';
        DATTXT = DATTXT_C2;
        DATTOP = DATTOP_C2;
        SetLl (locale:%Dec(C2:5:0)) CWPMSGF;
        ReadE (locale:%Dec(C2:5:0)) CWPMSGF;
        Dow Not %Eof(CWPMSGF);
           If AktDat > MSG_FROM And AktDat < MSG_TO;
              MSG_IDC = %Char(MSG_ID);
              DATA = MSG_IDC + ' ' + MSG_TXT;
              ZLA += 1;
              MARKA = *Blanks;
              Write HS1212SA;
           EndIf;
           ReadE (locale:%Dec(C2:5:0)) CWPMSGF;
        EndDo;
     When FLAG04 = 'HS1212W6' AND FLAGX4 = 'C3 ';
        DATTXT = DATTXT_C3;
        DATTOP = DATTOP_C3;
        SetLl (locale:%Dec(C3:5:0)) CWPMSGF;
        ReadE (locale:%Dec(C3:5:0)) CWPMSGF;
        Dow Not %Eof(CWPMSGF);
           If AktDat > MSG_FROM And AktDat < MSG_TO;
              MSG_IDC = %Char(MSG_ID);
              DATA = MSG_IDC + ' ' + MSG_TXT;
              ZLA += 1;
              MARKA = *Blanks;
              Write HS1212SA;
           EndIf;
           ReadE (locale:%Dec(C3:5:0)) CWPMSGF;
        EndDo;
     When FLAG04 = 'HS1212W6' AND FLAGX4 = 'C4 ';
        DATTXT = DATTXT_C4;
        DATTOP = DATTOP_C4;
        SetLl (locale:%Dec(C4:5:0)) CWPMSGF;
        ReadE (locale:%Dec(C4:5:0)) CWPMSGF;
        Dow Not %Eof(CWPMSGF);
           If AktDat > MSG_FROM And AktDat < MSG_TO;
              MSG_IDC = %Char(MSG_ID);
              Chain (C2:A_C2:C3:A_C3:MSG_TYPE:MSG_ID) CWPMSRF;
              If %Found(CWPMSRF) Or A_C2 = *Blanks Or A_C3 = *Blanks Or
                 F11TXT = F111;
                 DATA = MSG_IDC + ' ' + MSG_TXT;
                 ZLA += 1;
                 MARKA = *Blanks;
                 Write HS1212SA;
              EndIf;
           EndIf;
